<script setup>
import AppLayout from '@/Layouts/AppLayout.vue';import { useForm } from '@inertiajs/vue3';import ScannerPanel from '@/Components/ScannerPanel.vue';
defineOptions({layout:AppLayout});
const form=useForm({first_name:'',last_name:'',birth_date:'',id_document_number:'',nationality:'',reason:'',location:'',source:'manual',status:'active',notes:'',raw_payload:''});
function applyScan(payload, source){ form.raw_payload=payload.raw || payload.text || ''; form.source=source; form.id_document_number=payload.documentNumber || payload.text || form.id_document_number; form.first_name=payload.firstName || form.first_name; form.last_name=payload.lastName || form.last_name; form.birth_date=payload.birthDate || form.birth_date; form.nationality=payload.nationality || form.nationality; }
</script>
<template><section class="grid gap-5 lg:grid-cols-[1fr,1fr]"><div class="card"><h1 class="mb-4 text-2xl font-bold">Register denied access</h1><form @submit.prevent="form.post('/blacklist')" class="space-y-3"><div class="grid gap-3 sm:grid-cols-2"><div><label class="label">First name</label><input v-model="form.first_name" class="input"></div><div><label class="label">Last name</label><input v-model="form.last_name" class="input"></div></div><div class="grid gap-3 sm:grid-cols-2"><div><label class="label">Birth date</label><input v-model="form.birth_date" class="input" type="date"></div><div><label class="label">Nationality</label><input v-model="form.nationality" class="input"></div></div><div><label class="label">ID / document number</label><input v-model="form.id_document_number" class="input" required></div><div><label class="label">Denied at location</label><input v-model="form.location" class="input" placeholder="Door / venue / event" required></div><div><label class="label">Reason</label><input v-model="form.reason" class="input" placeholder="Policy breach / ban / security decision" required></div><div><label class="label">Notes</label><textarea v-model="form.notes" class="input min-h-24"></textarea></div><div class="rounded-xl border border-amber-500/40 bg-amber-500/10 p-3 text-sm text-amber-100">Do not store more data than needed. Verify local privacy, GDPR, ID scanning and retention rules before production use.</div><button class="btn btn-primary w-full" :disabled="form.processing">Save blacklist entry</button><p v-for="(err,k) in form.errors" :key="k" class="text-sm text-red-300">{{err}}</p></form></div><ScannerPanel @scanned="applyScan" /></section></template>
